import{C as r,o as n,c as s,a5 as o,E as i}from"./chunks/framework.CW28V7p_.js";const p=JSON.parse('{"title":"4. JIPs & SIMD governance","description":"","frontmatter":{},"headers":[],"relativePath":"module-10/4-governance.md","filePath":"module-10/4-governance.md","lastUpdated":1780937944000}'),l={name:"module-10/4-governance.md"},m=Object.assign(l,{setup(c){const t={id:"m10-4-governance",title:"🧠 Mini-check: Governance",intro:"2 питання.",questions:[{type:"compare",q:"SIMD vs JIP — у чому різниця?",ideal:`SIMD (Solana Improvement Document): Solana Foundation governance proposals. Cluster-wide protocol changes. Examples: SIMD-0326 (Alpenglow consensus), other consensus/runtime changes. Affects entire Solana cluster.

JIP (Jito Improvement Proposal): Jito DAO governance. Jito-specific features. Examples: JIP-37 (BAM subsidy), JIP-28 (JitoSOL delegation), etc. Affects only Jito system + validators using Jito-Solana.

Different scopes:
- SIMD: Solana protocol level
- JIP: Jito application level

Both follow similar process: proposal → discussion period → vote → implementation if approved. SIMD voted by validators (stake-weighted). JIP voted by JTO token holders.`,explanation:"Module 10.4."},{type:"mcq",q:"Як LumLabs має writ про governance proposals (per content style memory)?",options:['Attribute clearly до source ("Jito announced X", не "we announced")','Avoid imperative voice ("you must do X")',"No em-dashes, minimal emoji",'Use "we" коли writing про Jito decisions'],correct:[0,1,2],explanation:"LumLabs external observer, не member Jito team. Module 10.4."}]};return(d,e)=>{const a=r("Quiz");return n(),s("div",null,[e[0]||(e[0]=o('<h1 id="_4-jips-simd-governance" tabindex="-1">4. JIPs &amp; SIMD governance <a class="header-anchor" href="#_4-jips-simd-governance" aria-label="Permalink to &quot;4. JIPs &amp; SIMD governance&quot;">​</a></h1><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>Solana ecosystem changes through formal governance:</p><ul><li><strong>SIMD</strong> (Solana Improvement Documents) — Solana Foundation level (protocol changes, e.g., SIMD-0326 Alpenglow)</li><li><strong>JIP</strong> (Jito Improvement Proposals) — Jito ecosystem level (BAM subsidies, JitoSOL delegation criteria)</li></ul><p>Validators participate як stakers і operators — sometimes vote (stake-weighted) на SIMDs, follow JIP impacts.</p><h2 id="simd-process" tabindex="-1">SIMD process <a class="header-anchor" href="#simd-process" aria-label="Permalink to &quot;SIMD process&quot;">​</a></h2><ol><li><strong>Proposal submitted</strong> to <a href="https://github.com/solana-foundation/solana-improvement-documents" target="_blank" rel="noreferrer">github.com/solana-foundation/solana-improvement-documents</a></li><li><strong>Discussion period</strong> (usually weeks) on GitHub + Discord</li><li><strong>Vote</strong> — validators sign-voting via vote TX flag</li><li><strong>Implementation</strong> if approved — included у future agave release</li><li><strong>Activation</strong> at specific epoch boundary</li></ol><p>Examples:</p><ul><li><strong>SIMD-0326</strong>: Alpenglow consensus protocol (твій community cluster тестує)</li><li>Various runtime improvements, fee changes, etc.</li></ul><h2 id="jip-process" tabindex="-1">JIP process <a class="header-anchor" href="#jip-process" aria-label="Permalink to &quot;JIP process&quot;">​</a></h2><ol><li><strong>Proposal submitted</strong> to <a href="https://gov.jito.network" target="_blank" rel="noreferrer">gov.jito.network</a></li><li><strong>Discussion period</strong> (typically 14 days)</li><li><strong>Vote on Realms</strong> — JTO token holders vote</li><li><strong>Implementation</strong> if approved</li></ol><p>Examples:</p><ul><li><strong>JIP-28</strong>: JitoSOL delegation, 100% tier active, ongoing</li><li><strong>JIP-31/37</strong>: Cash subsidy для BAM validators, hard cutoff Sept 30 2026</li></ul><h2 id="lumlabs-participation" tabindex="-1">LumLabs participation <a class="header-anchor" href="#lumlabs-participation" aria-label="Permalink to &quot;LumLabs participation&quot;">​</a></h2><p>Як validator operator:</p><ul><li><strong>SIMDs</strong>: monitor для protocol changes affecting validator setup/operation</li><li><strong>JIPs</strong>: monitor для subsidy/delegation criteria changes</li><li><strong>Write/comment</strong>: external observer perspective, не Jito/Foundation member</li></ul><h3 id="content-style-per-memory" tabindex="-1">Content style (per memory) <a class="header-anchor" href="#content-style-per-memory" aria-label="Permalink to &quot;Content style (per memory)&quot;">​</a></h3><p>З <code>feedback_lumlabs_content_style.md</code>:</p><ul><li>Attribute source: &quot;Jito announced X&quot; (не &quot;we announced&quot;)</li><li>No imperative voice: &quot;you must do X&quot; sounds як authority</li><li>No em-dashes, minimal emoji</li><li>Peer-to-peer voice, not from team з authority</li></ul><p>Twitter/blog/Discord content про JIPs/SIMDs має ці rules.</p><h2 id="where-to-track" tabindex="-1">Where to track <a class="header-anchor" href="#where-to-track" aria-label="Permalink to &quot;Where to track&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>What</th></tr></thead><tbody><tr><td>github.com/solana-foundation/solana-improvement-documents</td><td>All SIMD proposals + discussions</td></tr><tr><td>gov.jito.network</td><td>Jito proposals + voting</td></tr><tr><td>#governance Discord channels</td><td>Discussion</td></tr><tr><td>Forum.solana.com</td><td>Long-form discussion</td></tr></tbody></table><h2 id="mini-quiz" tabindex="-1">Mini-quiz <a class="header-anchor" href="#mini-quiz" aria-label="Permalink to &quot;Mini-quiz&quot;">​</a></h2>',23)),i(a,{data:t}),e[1]||(e[1]=o('<h2 id="glossary" tabindex="-1">Glossary <a class="header-anchor" href="#glossary" aria-label="Permalink to &quot;Glossary&quot;">​</a></h2><p><a href="/glossary#s"><code>SIMD</code></a>, <a href="/glossary#j"><code>JIP</code></a>, <a href="/glossary#r"><code>Realms</code></a>, <a href="/glossary#j"><code>JTO</code></a>, <a href="/glossary#s"><code>Stake-weighted vote</code></a></p><h2 id="external-refs" tabindex="-1">External refs <a class="header-anchor" href="#external-refs" aria-label="Permalink to &quot;External refs&quot;">​</a></h2><ul><li><a href="https://github.com/solana-foundation/solana-improvement-documents" target="_blank" rel="noreferrer">SIMD repository</a></li><li><a href="https://gov.jito.network" target="_blank" rel="noreferrer">Jito Governance</a></li></ul><hr><p><strong>Попередньо:</strong> <a href="/module-10/3-doublezero">← 3. DoubleZero</a> | <strong>Наступне:</strong> <a href="/module-10/final-quiz">⭐ Final quiz →</a></p>',6))])}}});export{p as __pageData,m as default};
